Node.jsでPostgreSQLのコネクションプーリングをセットアップする方法をご説明します。

## 1. 必要なパッケージのインストール

```bash
npm install pg
# TypeScriptを使用する場合
npm install @types/pg --save-dev
```

## 2. 基本的なコネクションプールの設定

```javascript
const { Pool } = require('pg');

// コネクションプールの作成
const pool = new Pool({
  user: 'your_username',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,

  // プール設定
  max: 20,          // 最大接続数
  min: 5,           // 最小接続数
  idleTimeoutMillis: 30000,    // アイドル接続のタイムアウト（30秒）
  connectionTimeoutMillis: 2000, // 接続タイムアウト（2秒）
  maxUses: 7500,    // 接続の最大使用回数
});
```

## 3. 環境変数を使用した設定

```javascript
// .envファイル
// DATABASE_URL=postgresql://username:password@localhost:5432/database_name

const { Pool } = require('pg');

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});
```

## 4. クエリの実行方法

### 基本的なクエリ実行

```javascript
// SELECT クエリの例
async function getUsers() {
  try {
    const result = await pool.query('SELECT * FROM users WHERE active = $1', [true]);
    return result.rows;
  } catch (err) {
    console.error('Query error:', err);
    throw err;
  }
}

// INSERT クエリの例
async function createUser(name, email) {
  try {
    const result = await pool.query(
      'INSERT INTO users (name, email) VALUES ($1, $2) RETURNING *',
      [name, email]
    );
    return result.rows[0];
  } catch (err) {
    console.error('Insert error:', err);
    throw err;
  }
}
```

### トランザクションの処理

```javascript
async function transferMoney(fromUserId, toUserId, amount) {
  const client = await pool.connect();

  try {
    await client.query('BEGIN');

    // 送金者の残高を減らす
    await client.query(
      'UPDATE accounts SET balance = balance - $1 WHERE user_id = $2',
      [amount, fromUserId]
    );

    // 受取人の残高を増やす
    await client.query(
      'UPDATE accounts SET balance = balance + $1 WHERE user_id = $2',
      [amount, toUserId]
    );

    await client.query('COMMIT');
    console.log('Transfer completed successfully');

  } catch (err) {
    await client.query('ROLLBACK');
    console.error('Transfer failed:', err);
    throw err;
  } finally {
    client.release(); // 重要: コネクションをプールに戻す
  }
}
```

## 5. より完全な設定例

```javascript
const { Pool } = require('pg');

class DatabaseService {
  constructor() {
    this.pool = new Pool({
      user: process.env.DB_USER || 'postgres',
      host: process.env.DB_HOST || 'localhost',
      database: process.env.DB_NAME || 'myapp',
      password: process.env.DB_PASSWORD,
      port: process.env.DB_PORT || 5432,

      // SSL設定（本番環境で推奨）
      ssl: process.env.NODE_ENV === 'production' ? { rejectUnauthorized: false } : false,

      // プール設定
      max: parseInt(process.env.DB_POOL_MAX) || 20,
      min: parseInt(process.env.DB_POOL_MIN) || 5,
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 2000,
      maxUses: 7500,
    });

    // イベントリスナーの設定
    this.pool.on('connect', (client) => {
      console.log('New client connected to database');
    });

    this.pool.on('error', (err) => {
      console.error('Database pool error:', err);
    });
  }

  async query(text, params) {
    const start = Date.now();
    try {
      const result = await this.pool.query(text, params);
      const duration = Date.now() - start;
      console.log('Query executed:', { text, duration, rows: result.rowCount });
      return result;
    } catch (err) {
      console.error('Query error:', { text, error: err.message });
      throw err;
    }
  }

  async getClient() {
    return await this.pool.connect();
  }

  async end() {
    await this.pool.end();
  }
}

// シングルトンとして使用
const db = new DatabaseService();
module.exports = db;
```

## 6. Express.jsでの使用例

```javascript
const express = require('express');
const db = require('./database'); // 上記のDatabaseServiceファイル

const app = express();
app.use(express.json());

// ユーザー一覧取得
app.get('/users', async (req, res) => {
  try {
    const result = await db.query('SELECT id, name, email FROM users');
    res.json(result.rows);
  } catch (err) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// ユーザー作成
app.post('/users', async (req, res) => {
  const { name, email } = req.body;

  try {
    const result = await db.query(
      'INSERT INTO users (name, email) VALUES ($1, $2) RETURNING *',
      [name, email]
    );
    res.status(201).json(result.rows[0]);
  } catch (err) {
    res.status(400).json({ error: 'Bad request' });
  }
});

// アプリケーション終了時のクリーンアップ
process.on('SIGTERM', async () => {
  console.log('Closing database pool...');
  await db.end();
  process.exit(0);
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
```

## 7. 重要なポイント

### コネクションの適切な管理
```javascript
// ❌ 悪い例 - コネクションがリークする可能性
const client = await pool.connect();
const result = await client.query('SELECT * FROM users');
// client.release() を忘れている

// ✅ 良い例 - try-finallyでリソースを確実に解放
const client = await pool.connect();
try {
  const result = await client.query('SELECT * FROM users');
  return result.rows;
} finally {
  client.release();
}
```

### エラーハンドリング
```javascript
pool.on('error', (err) => {
  console.error('Unexpected error on idle client', err);
  process.exit(-1);
});
```

