    return result.rows[0];
  } catch (error) {
    console.error('Database insert error:', error);
    throw error;
  }
}
```

## 5. トランザクションの使用

```javascript
async function transferMoney(fromUserId, toUserId, amount) {
  const client = await pool.connect();

  try {
    await client.query('BEGIN');

    // 送金者の残高を減らす
    await client.query(
      'UPDATE accounts SET balance = balance - $1 WHERE user_id = $2',
      [amount, fromUserId]
    );

    // 受取人の残高を増やす
    await client.query(
      'UPDATE accounts SET balance = balance + $1 WHERE user_id = $2',
      [amount, toUserId]
    );

    await client.query('COMMIT');
    console.log('Transaction completed successfully');
  } catch (error) {
    await client.query('ROLLBACK');
    console.error('Transaction failed:', error);
    throw error;
  } finally {
    client.release();
  }
}
```

## 6. エラーハンドリングとログ設定

```javascript
const pool = new Pool({
  // ... 基本設定
});

// プールのイベントリスナー
pool.on('connect', (client) => {
  console.log('New client connected');
});

pool.on('error', (err, client) => {
  console.error('Unexpected error on idle client:', err);
});

// アプリケーション終了時の処理
process.on('SIGTERM', () => {
  console.log('SIGTERM signal received: closing HTTP server');
  pool.end(() => {
    console.log('Database pool closed');
  });
});
```

## 7. TypeScript版の実装

```typescript
import { Pool, PoolClient, QueryResult } from 'pg';

interface User {
  id: number;
  name: string;
  email: string;
}

class DatabaseService {
  private pool: Pool;

  constructor() {
    this.pool = new Pool({
      user: process.env.DB_USER,
      host: process.env.DB_HOST,
      database: process.env.DB_NAME,
      password: process.env.DB_PASSWORD,
      port: parseInt(process.env.DB_PORT || '5432'),
      max: 20,
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 2000,
    });
  }

  async getUsers(): Promise<User[]> {
    try {
      const result: QueryResult<User> = await this.pool.query('SELECT * FROM users');
      return result.rows;
    } catch (error) {
      console.error('Database query error:', error);
      throw error;
    }
  }

  async close(): Promise<void> {
    await this.pool.end();
  }
}

export default DatabaseService;
```

## 8. パフォーマンスのベストプラクティス

```javascript
// プリペアドステートメントの使用
const getUserQuery = {
  name: 'get-user',
  text: 'SELECT * FROM users WHERE id = $1',
};

async function getUserOptimized(id) {
  try {
    const result = await pool.query(getUserQuery, [id]);
    return result.rows[0];
  } catch (error) {
    console.error('Database query error:', error);
    throw error;
  }
}
```

この設定により、効率的で安全なPostgreSQLのコネクションプーリングが実現できます。プール設定は、アプリケーションの負荷に応じて調整してください。

