normal_texts:
コールバック地獄をasync/awaitにリファクタリングする例をいくつか紹介します。

## 1. 基本的な例

### Before (コールバック地獄)
```javascript
function fetchUserData(userId, callback) {
  getUserById(userId, (err, user) => {
    if (err) {
      callback(err, null);
      return;
    }

    getPostsByUserId(user.id, (err, posts) => {
      if (err) {
        callback(err, null);
        return;
      }

      getCommentsForPosts(posts, (err, comments) => {
        if (err) {
          callback(err, null);
          return;
        }

        callback(null, { user, posts, comments });
      });
    });
  });
}
```

### After (async/await)
```javascript
async function fetchUserData(userId) {
  try {
    const user = await getUserById(userId);
    const posts = await getPostsByUserId(user.id);
    const comments = await getCommentsForPosts(posts);

    return { user, posts, comments };
  } catch (error) {
    throw error;
  }
}
```

## 2. ファイル操作の例

### Before (コールバック地獄)
```javascript
const fs = require('fs');

function processFiles(callback) {
  fs.readFile('file1.txt', 'utf8', (err, data1) => {
    if (err) {
      callback(err);
      return;
    }

    fs.readFile('file2.txt', 'utf8', (err, data2) => {
      if (err) {
        callback(err);
        return;
      }

      const combined = data1 + data2;

      fs.writeFile('output.txt', combined, (err) => {
        if (err) {
          callback(err);
          return;
        }

        callback(null, 'Files processed successfully');
      });
    });
  });
}
```

### After (async/await)
```javascript
const fs = require('fs').promises;

async function processFiles() {
  try {
    const data1 = await fs.readFile('file1.txt', 'utf8');
    const data2 = await fs.readFile('file2.txt', 'utf8');
    const combined = data1 + data2;

    await fs.writeFile('output.txt', combined);

    return 'Files processed successfully';
  } catch (error) {
    throw error;
  }
}
```

## 3. 複数の非同期処理を並行実行

### Before (コールバック地獄)
```javascript
function fetchAllData(callback) {
  let results = {};
  let completed = 0;

  fetchUsers((err, users) => {
    if (err) {
      callback(err);
      return;
    }
    results.users = users;
    completed++;
    if (completed === 3) callback(null, results);
  });

  fetchPosts((err, posts) => {
    if (err) {
      callback(err);
      return;
    }
    results.posts = posts;
    completed++;
    if (completed === 3) callback(null, results);
  });

  fetchCategories((err, categories) => {
    if (err) {
      callback(err);
      return;
    }
    results.categories = categories;
    completed++;
    if (completed === 3) callback(null, results);
  });
}
```

### After (async/await with Promise.all)
```javascript
async function fetchAllData() {
  try {
    const [users, posts, categories] = await Promise.all([
      fetchUsers(),
      fetchPosts(),
      fetchCategories()
    ]);

    return { users, posts, categories };
  } catch (error) {
    throw error;
  }
}
```

## 4. 段階的なデータ処理

### Before (コールバック地獄)
```javascript
function authenticateAndFetchData(credentials, callback) {
  authenticate(credentials, (err, token) => {
    if (err) {
      callback(err);
      return;
    }

    validateToken(token, (err, isValid) => {
      if (err) {
        callback(err);
        return;
      }

      if (!isValid) {
        callback(new Error('Invalid token'));
        return;
      }

      fetchUserProfile(token, (err, profile) => {
        if (err) {
          callback(err);
          return;
        }

        fetchUserPermissions(profile.id, (err, permissions) => {
          if (err) {
            callback(err);
            return;
          }

          callback(null, { profile, permissions, token });
        });
      });
    });
  });
}
```

### After (async/await)
```javascript
async function authenticateAndFetchData(credentials) {
  try {
    const token = await authenticate(credentials);
    const isValid = await validateToken(token);

    if (!isValid) {
      throw new Error('Invalid token');
    }

    const profile = await fetchUserProfile(token);
    const permissions = await fetchUserPermissions(profile.id);

    return { profile, permissions, token };
  } catch (error) {
    throw error;
  }
}
```

## 5. 使用例

```javascript
// async/await版の使用
async function main() {
  try {
    const userData = await fetchUserData(123);
    console.log('User data:', userData);

    const fileResult = await processFiles();
    console.log(fileResult);

    const allData = await fetchAllData();
    console.log('All data:', allData);

  } catch (error) {
    console.error('Error:', error.message);
  }
}

main();
```

## リファクタリングの利点

1. **可読性の向上**: ネストが浅くなり、コードが読みやすくなる
2. **エラーハンドリングの簡素化**: try/catchで統一的に処理できる
3. **デバッグの容易さ**: スタックトレースが分かりやすくなる
4. **保守性の向上**: コードの変更や拡張が容易になる

このように、async/awaitを使用することでコールバック地獄を解消し、より読みやすく保守しやすいコードにリファクタリングできます。

コールバック地獄をasync/awaitにリファクタリングする方法を説明します。

## コールバック地獄の例

まず、典型的なコールバック地獄の例を見てみましょう：

```javascript
// コールバック地獄の例
function fetchUserData(userId, callback) {
  getUserById(userId, (err, user) => {
    if (err) {
      callback(err, null);
      return;
    }

    getPostsByUserId(user.id, (err, posts) => {
      if (err) {
        callback(err, null);
        return;
      }

      getCommentsByPostId(posts[0].id, (err, comments) => {
        if (err) {
          callback(err, null);
          return;
        }

        getUserById(comments[0].authorId, (err, author) => {
          if (err) {
            callback(err, null);
            return;
          }

          callback(null, {
            user,
            posts,
            comments,
            commentAuthor: author
          });
        });
      });
    });
  });
}
```

## async/awaitにリファクタリング

### ステップ1: コールバック関数をPromiseに変換

```javascript
// コールバック関数をPromise化
function getUserById(userId) {
  return new Promise((resolve, reject) => {
    // 既存のコールバック関数をラップ
    originalGetUserById(userId, (err, user) => {
      if (err) reject(err);
      else resolve(user);
    });
  });
}

function getPostsByUserId(userId) {
  return new Promise((resolve, reject) => {
    originalGetPostsByUserId(userId, (err, posts) => {
      if (err) reject(err);
      else resolve(posts);
    });
  });
}

function getCommentsByPostId(postId) {
  return new Promise((resolve, reject) => {
    originalGetCommentsByPostId(postId, (err, comments) => {
      if (err) reject(err);
      else resolve(comments);
    });
  });
}
```

### ステップ2: async/awaitで書き直し

```javascript
async function fetchUserData(userId) {
  try {
    // 順次実行
    const user = await getUserById(userId);
    const posts = await getPostsByUserId(user.id);
    const comments = await getCommentsByPostId(posts[0].id);
    const commentAuthor = await getUserById(comments[0].authorId);

    return {
      user,
      posts,
      comments,
      commentAuthor
    };
  } catch (error) {
    throw error;
  }
}
```

## より実践的な例

### Node.jsのファイル操作の場合

```javascript
// コールバック地獄
const fs = require('fs');

function processFiles(callback) {
  fs.readFile('input.txt', 'utf8', (err, data) => {
    if (err) {
      callback(err);
      return;
    }

    const processedData = data.toUpperCase();

    fs.writeFile('output.txt', processedData, (err) => {
      if (err) {
        callback(err);
        return;
      }

      fs.readFile('output.txt', 'utf8', (err, finalData) => {
        if (err) {
          callback(err);
          return;
        }

        callback(null, finalData);
      });
    });
  });
}
```

```javascript
// async/awaitバージョン
const fs = require('fs').promises;

async function processFiles() {
  try {
    const data = await fs.readFile('input.txt', 'utf8');
    const processedData = data.toUpperCase();
    await fs.writeFile('output.txt', processedData);
    const finalData = await fs.readFile('output.txt', 'utf8');
    return finalData;
  } catch (error) {
    throw error;
  }
}
```

## 並列処理が可能な場合

```javascript
// 直列実行（遅い）
async function fetchUserDataSerial(userIds) {
  const users = [];
  for (const id of userIds) {
    const user = await getUserById(id);
    users.push(user);
  }
  return users;
}

// 並列実行（速い）
async function fetchUserDataParallel(userIds) {
  const userPromises = userIds.map(id => getUserById(id));
  const users = await Promise.all(userPromises);
  return users;
}
```

## エラーハンドリングの改善

```javascript
async function fetchUserDataWithErrorHandling(userId) {
  try {
    const user = await getUserById(userId);

    if (!user) {
      throw new Error('ユーザーが見つかりません');
    }

    const posts = await getPostsByUserId(user.id);

    // 投稿がない場合のハンドリング
    if (posts.length === 0) {
      return { user, posts: [], comments: [], commentAuthor: null };
    }

    const comments = await getCommentsByPostId(posts[0].id);

    if (comments.length === 0) {
      return { user, posts, comments: [], commentAuthor: null };
    }

    const commentAuthor = await getUserById(comments[0].authorId);

    return {
      user,
      posts,
      comments,
      commentAuthor
    };

  } catch (error) {
    console.error('データ取得エラー:', error);
    throw new Error(`ユーザーデータの取得に失敗しました: ${error.message}`);
  }
}
```

## 使用例

```javascript
// 使用方法
async function main() {
  try {
    const userData = await fetchUserData(123);
    console.log('取得完了:', userData);
  } catch (error) {
    console.error('エラー:', error);
  }
}

main();
```

## リファクタリングのメリット

1. **可読性の向上**: ネストが深くならず、コードが読みやすい
2. **エラーハンドリングの簡素化**: try-catchで一箇所でエラー処理が可能
3. **デバッグの容易さ**: スタックトレースが追いやすい
4. **保守性の向上**: コードの修正や追加が簡単

このようにasync/awaitを使うことで、コールバック地獄を解消し、より読みやすく保守しやすいコードにリファクタリングできます。

コールバック地獄をasync/awaitにリファクタリングする方法を説明します。

## コールバック地獄の例

まず、典型的なコールバック地獄の例を見てみましょう：

```javascript
// コールバック地獄の例
function fetchUserData(userId, callback) {
  getUserById(userId, (err, user) => {
    if (err) {
      callback(err, null);
      return;
    }

    getUserProfile(user.id, (err, profile) => {
      if (err) {
        callback(err, null);
        return;
      }

      getUserPosts(user.id, (err, posts) => {
        if (err) {
          callback(err, null);
          return;
        }

        getPostComments(posts[0].id, (err, comments) => {
          if (err) {
            callback(err, null);
            return;
          }

          callback(null, {
            user: user,
            profile: profile,
            posts: posts,
            comments: comments
          });
        });
      });
    });
  });
}
```

## async/awaitにリファクタリング

### 1. Promise化する

まず、コールバック関数をPromiseに変換します：

```javascript
// Promiseベースの関数を作成
function getUserByIdPromise(userId) {
  return new Promise((resolve, reject) => {
    getUserById(userId, (err, user) => {
      if (err) reject(err);
      else resolve(user);
    });
  });
}

function getUserProfilePromise(userId) {
  return new Promise((resolve, reject) => {
    getUserProfile(userId, (err, profile) => {
      if (err) reject(err);
      else resolve(profile);
    });
  });
}

function getUserPostsPromise(userId) {
  return new Promise((resolve, reject) => {
    getUserPosts(userId, (err, posts) => {
      if (err) reject(err);
      else resolve(posts);
    });
  });
}

function getPostCommentsPromise(postId) {
  return new Promise((resolve, reject) => {
    getPostComments(postId, (err, comments) => {
      if (err) reject(err);
      else resolve(comments);
    });
  });
}
```

### 2. async/awaitを使用してリファクタリング

```javascript
// async/awaitを使用したクリーンなコード
async function fetchUserData(userId) {
  try {
    const user = await getUserByIdPromise(userId);
    const profile = await getUserProfilePromise(user.id);
    const posts = await getUserPostsPromise(user.id);
    const comments = await getPostCommentsPromise(posts[0].id);

    return {
      user: user,
      profile: profile,
      posts: posts,
      comments: comments
    };
  } catch (error) {
    throw error;
  }
}
```

## より実践的な例

### ファイル操作の例

```javascript
// Before: コールバック地獄
const fs = require('fs');

function processFiles(callback) {
  fs.readFile('input.txt', 'utf8', (err, data) => {
    if (err) {
      callback(err, null);
      return;
    }

    const processedData = data.toUpperCase();

    fs.writeFile('output.txt', processedData, (err) => {
      if (err) {
        callback(err, null);
        return;
      }

      fs.readFile('output.txt', 'utf8', (err, result) => {
        if (err) {
          callback(err, null);
          return;
        }

        callback(null, result);
      });
    });
  });
}
```

```javascript
// After: async/await
const fs = require('fs').promises;

async function processFiles() {
  try {
    const data = await fs.readFile('input.txt', 'utf8');
    const processedData = data.toUpperCase();
    await fs.writeFile('output.txt', processedData);
    const result = await fs.readFile('output.txt', 'utf8');
    return result;
  } catch (error) {
    throw error;
  }
}
```

## 並列処理の最適化

複数の非同期処理が独立している場合は、`Promise.all`を使用できます：

```javascript
// 順次処理（遅い）
async function fetchUserDataSequential(userId) {
  try {
    const user = await getUserByIdPromise(userId);
    const profile = await getUserProfilePromise(user.id);
    const posts = await getUserPostsPromise(user.id);
    // profile と posts は独立しているので並列実行可能

    return { user, profile, posts };
  } catch (error) {
    throw error;
  }
}

// 並列処理（速い）
async function fetchUserDataParallel(userId) {
  try {
    const user = await getUserByIdPromise(userId);

    // profile と posts を並列で取得
    const [profile, posts] = await Promise.all([
      getUserProfilePromise(user.id),
      getUserPostsPromise(user.id)
    ]);

    return { user, profile, posts };
  } catch (error) {
    throw error;
  }
}
```

## 使用例

```javascript
// 使用方法
async function main() {
  try {
    const userData = await fetchUserData(123);
    console.log('ユーザーデータ:', userData);
  } catch (error) {
    console.error('エラーが発生しました:', error);
  }
}

main();
```

## メリット

1. **可読性の向上**: ネストが深くならずコードが読みやすい
2. **エラーハンドリングの簡素化**: try-catchで統一的に処理
3. **デバッグのしやすさ**: スタックトレースが分かりやすい
4. **保守性の向上**: コードの変更や追加が容易

async/awaitを使用することで、コールバック地獄から解放され、同期的なコードのように書けるようになります。

