ReactのError Boundaryを実装する方法をご説明します。

## 基本的なError Boundaryの実装

### 1. クラスコンポーネントでの実装

```jsx
import React from 'react';

class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { 
      hasError: false,
      error: null,
      errorInfo: null
    };
  }

  static getDerivedStateFromError(error) {
    // エラーが発生した際にstateを更新してフォールバックUIを表示
    return { hasError: true };
  }

  componentDidCatch(error, errorInfo) {
    // エラー情報をログに記録
    console.error('Error Boundary caught an error:', error, errorInfo);

    this.setState({
      error: error,
      errorInfo: errorInfo
    });

    // エラー報告サービスに送信（例：Sentry, LogRocket等）
    // this.logErrorToService(error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      // カスタムフォールバックUIを表示
      return (
        <div style={{ padding: '20px', textAlign: 'center' }}>
          <h2>申し訳ありません。エラーが発生しました。</h2>
          <details style={{ whiteSpace: 'pre-wrap', marginTop: '20px' }}>
            <summary>エラー詳細（デバッグ用）</summary>
            {this.state.error && this.state.error.toString()}
            <br />
            {this.state.errorInfo.componentStack}
          </details>
          <button 
            onClick={() => this.setState({ hasError: false, error: null, errorInfo: null })}
            style={{ marginTop: '20px', padding: '10px 20px' }}
          >
            再試行
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;
```

### 2. より高機能なError Boundary

```jsx
import React from 'react';
import PropTypes from 'prop-types';

class AdvancedErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null,
      eventId: null
    };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true };
  }

  componentDidCatch(error, errorInfo) {
    const errorDetails = {
      error: error.toString(),
      stack: error.stack,
      componentStack: errorInfo.componentStack,
      timestamp: new Date().toISOString(),
      userAgent: navigator.userAgent,
      url: window.location.href
    };

    // エラーログをサービスに送信
    this.logError(errorDetails);

    this.setState({
      error,
      errorInfo,
      eventId: this.generateEventId()
    });
  }

  logError = (errorDetails) => {
    if (this.props.onError) {
      this.props.onError(errorDetails);
    }

    // 開発環境でのログ出力
    if (process.env.NODE_ENV === 'development') {
      console.group('🚨 Error Boundary');
      console.error('Error:', errorDetails.error);
      console.error('Stack:', errorDetails.stack);
      console.error('Component Stack:', errorDetails.componentStack);
      console.groupEnd();
    }
  };

  generateEventId = () => {
    return Math.random().toString(36).substr(2, 9);
  };

  handleRetry = () => {
    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
      eventId: null
    });
  };

  render() {
    if (this.state.hasError) {
      // カスタムエラーコンポーネントが提供されている場合
      if (this.props.fallback) {
        return this.props.fallback({
          error: this.state.error,
          errorInfo: this.state.errorInfo,
          eventId: this.state.eventId,
          retry: this.handleRetry
        });
      }

      // デフォルトのエラーUI
      return (
        <div className="error-boundary">
          <div className="error-content">
            <h1>🚨 エラーが発生しました</h1>
            <p>申し訳ありませんが、予期しないエラーが発生しました。</p>

            {this.props.showDetails && (
              <div className="error-details">
                <h3>エラー詳細:</h3>
                <pre>{this.state.error.toString()}</pre>
                <h3>コンポーネントスタック:</h3>
                <pre>{this.state.errorInfo.componentStack}</pre>
              </div>
            )}

            <div className="error-actions">
              <button onClick={this.handleRetry} className="retry-button">
                再試行
              </button>
              <button onClick={() => window.location.reload()} className="reload-button">
                ページを再読み込み
              </button>
            </div>

            {this.state.eventId && (
              <p className="error-id">エラーID: {this.state.eventId}</p>
            )}
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

AdvancedErrorBoundary.propTypes = {
  children: PropTypes.node.isRequired,
  fallback: PropTypes.func,
  onError: PropTypes.func,
  showDetails: PropTypes.bool
};

AdvancedErrorBoundary.defaultProps = {
  showDetails: process.env.NODE_ENV === 'development'
};

export default AdvancedErrorBoundary;
```

