```jsx
import React from 'react';
import { ErrorBoundary } from 'react-error-boundary';

function ErrorFallback({error, resetErrorBoundary}) {
  return (
    <div role="alert" style={{ padding: '20px', textAlign: 'center' }}>
      <h2>エラーが発生しました</h2>
      <pre style={{ color: 'red' }}>{error.message}</pre>
      <button onClick={resetErrorBoundary}>再試行</button>
    </div>
  );
}

const App = () => {
  return (
    <ErrorBoundary
      FallbackComponent={ErrorFallback}
      onError={(error, errorInfo) => {
        console.log('Error logged:', error, errorInfo);
      }}
      onReset={() => {
        // エラーリセット時の処理
        console.log('Error boundary reset');
      }}
    >
      <BuggyComponent />
    </ErrorBoundary>
  );
};
```

## 重要なポイント

1. **Error Boundaryはクラスコンポーネントでのみ実装可能**（現在のところ）
2. **イベントハンドラー内のエラーはキャッチできない**
3. **非同期コード（setTimeout、Promiseなど）のエラーはキャッチできない**
4. **開発環境と本番環境で異なる動作をする**
5. **エラーログの収集とレポートが重要**

このError Boundaryを使用することで、アプリケーション全体がクラッシュすることを防ぎ、ユーザーエクスペリエンスを向上させることができます。

ReactのError Boundaryの実装例をいくつかのパターンで紹介します。

## 基本的なError Boundary

```jsx
import React from 'react';

class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error) {
    // エラーが発生した時にstateを更新
    return { hasError: true };
  }

  componentDidCatch(error, errorInfo) {
    // エラーログを記録
    console.error('Error Boundary caught an error:', error, errorInfo);

    this.setState({
      error: error,
      errorInfo: errorInfo
    });

    // エラー報告サービスに送信（例：Sentry, Bugsnag等）
    // logErrorToService(error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: '20px', textAlign: 'center' }}>
          <h2>申し訳ございません。エラーが発生しました。</h2>
          <p>ページを再読み込みしてお試しください。</p>

          {/* 開発環境でのみエラー詳細を表示 */}
          {process.env.NODE_ENV === 'development' && (
            <details style={{ marginTop: '20px', textAlign: 'left' }}>
              <summary>エラー詳細（開発用）</summary>
              <pre style={{ backgroundColor: '#f5f5f5', padding: '10px', overflow: 'auto' }}>
                {this.state.error && this.state.error.toString()}
                <br />
                {this.state.errorInfo.componentStack}
              </pre>
            </details>
          )}

          <button 
            onClick={() => window.location.reload()}
            style={{
              marginTop: '20px',
              padding: '10px 20px',
              backgroundColor: '#007bff',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            ページを再読み込み
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;
```

## カスタマイズ可能なError Boundary

```jsx
import React from 'react';

class CustomErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, errorInfo) {
    // エラーログ記録
    console.error('Error caught by boundary:', error, errorInfo);

    // カスタムエラーハンドラーを実行
    if (this.props.onError) {
      this.props.onError(error, errorInfo);
    }
  }

  handleReset = () => {
    this.setState({ hasError: false, error: null });
    if (this.props.onReset) {
      this.props.onReset();
    }
  };

  render() {
    if (this.state.hasError) {
      // カスタムフォールバックUIがある場合はそれを使用
      if (this.props.fallback) {
        return this.props.fallback(this.state.error, this.handleReset);
      }

      // デフォルトのエラーUI
      return (
        <div className="error-boundary">
          <div className="error-content">
            <h2>{this.props.title || 'エラーが発生しました'}</h2>
            <p>{this.props.message || 'アプリケーションでエラーが発生しました。'}</p>

            {this.props.showResetButton !== false && (
              <button 
                onClick={this.handleReset}
                className="error-reset-button"
              >
                リトライ
              </button>
            )}
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export default CustomErrorBoundary;
```

## React Hooksベースのエラーハンドリング

```jsx
import { useState, useEffect } from 'react';

// エラーを投げるカスタムフック
export const useErrorHandler = () => {
  const [error, setError] = useState(null);

  const resetError = () => setError(null);

  const captureError = (error) => {
    setError(error);
  };

  useEffect(() => {
    if (error) {
      throw error;
    }
  }, [error]);

  return { captureError, resetError };
};

// 使用例のコンポーネント
const ExampleComponent = () => {
  const { captureError } = useErrorHandler();

  const handleAsyncError = async () => {
    try {
      // 非同期処理
      await someAsyncOperation();
    } catch (error) {
      captureError(error); // Error Boundaryでキャッチされる
    }
  };

  return (
    <div>
      <button onClick={handleAsyncError}>
        非同期処理を実行
      </button>
    </div>
  );
};
```

## 実際の使用例

```jsx
import React from 'react';
import ErrorBoundary from './ErrorBoundary';

// エラーが発生する可能性のあるコンポーネント
const ProblematicComponent = () => {
  const [shouldError, setShouldError] = React.useState(false);

  if (shouldError) {
    throw new Error('意図的なエラーです！');
  }

  return (
    <div>
      <h3>正常なコンポーネント</h3>
      <button onClick={() => setShouldError(true)}>
        エラーを発生させる
      </button>
    </div>
  );
};

// アプリケーションでの使用
const App = () => {
  return (
    <div>
      <h1>React Error Boundary デモ</h1>

      {/* 基本的な使用 */}
      <ErrorBoundary>
        <ProblematicComponent />
      </ErrorBoundary>

      {/* カスタマイズされた使用 */}
      <CustomErrorBoundary
        title="カスタムエラー"
        message="このセクションでエラーが発生しました。"
        onError={(error, errorInfo) => {
          console.log('Custom error handler:', error);
          // エラー報告サービスに送信
        }}
        fallback={(error, reset) => (
          <div style={{ border: '2px solid red', padding: '10px', margin: '10px' }}>
            <h3>🚨 カスタムエラー画面</h3>
            <p>エラー: {error.message}</p>
            <button onClick={reset}>リセット</button>
          </div>
        )}
      >
        <ProblematicComponent />
      </CustomErrorBoundary>
    </div>
  );
};

export default App;
```

## Error Boundary用のCSS

```css
