Nginxのリバースプロキシ設定について説明します。

## 基本設定

### 1. 基本的なリバースプロキシ設定

```nginx
server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://backend_server;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}

upstream backend_server {
    server 127.0.0.1:3000;
}
```

### 2. 複数のバックエンドサーバーへのロードバランシング

```nginx
upstream backend {
    server 192.168.1.10:3000 weight=3;
    server 192.168.1.11:3000 weight=2;
    server 192.168.1.12:3000 weight=1;
}

server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://backend;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    }
}
```

## よく使用されるプロキシディレクティブ

### 3. 詳細なプロキシ設定

```nginx
server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://backend;

        # ヘッダー設定
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # タイムアウト設定
        proxy_connect_timeout 30s;
        proxy_send_timeout 30s;
        proxy_read_timeout 30s;

        # バッファリング設定
        proxy_buffering on;
        proxy_buffer_size 4k;
        proxy_buffers 8 4k;

        # その他の設定
        proxy_redirect off;
        proxy_http_version 1.1;
        proxy_set_header Connection "";
    }
}
```

## パスベースのプロキシ設定

### 4. 複数のサービスへの振り分け

```nginx
server {
    listen 80;
    server_name example.com;

    # API サーバー
    location /api/ {
        proxy_pass http://api_server/;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
    }

    # 静的ファイルサーバー
    location /static/ {
        proxy_pass http://static_server/;
    }

    # メインアプリケーション
    location / {
        proxy_pass http://app_server;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
    }
}

upstream api_server {
    server 127.0.0.1:8001;
}

upstream static_server {
    server 127.0.0.1:8002;
}

upstream app_server {
    server 127.0.0.1:3000;
}
```

## SSL/HTTPS対応

### 5. HTTPS リバースプロキシ設定

```nginx
server {
    listen 443 ssl http2;
    server_name example.com;

    ssl_certificate /path/to/certificate.crt;
    ssl_certificate_key /path/to/private.key;

    location / {
        proxy_pass http://backend;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto https;
        proxy_ssl_verify off;
    }
}

# HTTP から HTTPS へのリダイレクト
server {
    listen 80;
    server_name example.com;
    return 301 https://$server_name$request_uri;
}
```

## WebSocket対応

### 6. WebSocket プロキシ設定

```nginx
location /websocket {
    proxy_pass http://websocket_backend;
    proxy_http_version 1.1;
    proxy_set_header Upgrade $http_upgrade;
    proxy_set_header Connection "upgrade";
    proxy_set_header Host $host;
    proxy_set_header X-Real-IP $remote_addr;
    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    proxy_cache_bypass $http_upgrade;
}
```

## ヘルスチェックと高可用性

### 7. ヘルスチェック付きアップストリーム

```nginx
upstream backend {
    server 192.168.1.10:3000 max_fails=3 fail_timeout=30s;
    server 192.168.1.11:3000 max_fails=3 fail_timeout=30s backup;
    server 192.168.1.12:3000 down;
}
```

## エラーハンドリング

### 8. カスタムエラーページとフォールバック

```nginx
server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://backend;
        proxy_set_header Host $host;

        # エラー時の処理
        error_page 502 503 504 /50x.html;
        proxy_next_upstream error timeout http_502 http_503 http_504;
    }

    location = /50x.html {
        root /usr/share/nginx/html;
    }
}
```

## パフォーマンス最適化

### 9. キャッシュとパフォーマンス設定

```nginx
proxy_cache_path /var/cache/nginx levels=1:2 keys_zone=my_cache:10m;

server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://backend;
        proxy_cache my_cache;
        proxy_cache_valid 200 1h;
        proxy_cache_valid 404 1m;
        proxy_cache_bypass $http_cache_control;
        add_header X-Cache-Status $upstream_cache_status;
    }
}
```

これらの設定を参考に、あなたの環境に合わせて調整してください。何か特定の要件があれば、お気軽にお聞かせください。

