```

### クロージャによる参照保持
```javascript
// 悪い例
function createHandler() {
    const largeData = new Array(1000000).fill('data');

    return function(req, res) {
        // largeDataが参照されていなくても、クロージャで保持される
        res.send('Hello');
    };
}

// 良い例
function createHandler() {
    return function(req, res) {
        // 必要な時だけデータを作成
        const data = getSomeData();
        res.send('Hello');
    };
}
```

### グローバル変数の蓄積
```javascript
// 悪い例
let cache = {};
app.get('/data/:id', (req, res) => {
    cache[req.params.id] = fetchData(req.params.id); // 無制限に蓄積
    res.json(cache[req.params.id]);
});

// 良い例
