## 5. メモリリーク検出のヘルパー関数

```javascript
class MemoryMonitor {
  constructor(interval = 5000) {
    this.interval = interval;
    this.baseline = null;
    this.measurements = [];
  }

  start() {
    this.baseline = process.memoryUsage();
    this.timer = setInterval(() => {
      const current = process.memoryUsage();
      const growth = {
        heapUsed: current.heapUsed - this.baseline.heapUsed,
        heapTotal: current.heapTotal - this.baseline.heapTotal,
        rss: current.rss - this.baseline.rss,
        timestamp: Date.now()
      };

      this.measurements.push(growth);

      // 継続的な成長を検出
      if (this.measurements.length > 10) {
        const recent = this.measurements.slice(-10);
        const avgGrowth = recent.reduce((sum, m) => sum + m.heapUsed, 0) / 10;

        if (avgGrowth > 1024 * 1024) { // 1MB/measurement
          console.warn('Potential memory leak detected!', {
            avgGrowthMB: Math.round(avgGrowth / 1024 / 1024)
          });
        }
      }
    }, this.interval);
  }

  stop() {
    if (this.timer) clearInterval(this.timer);
  }
}

// 使用例
const monitor = new MemoryMonitor();
monitor.start();
```

