### 自動化された検出
```javascript
class MemoryLeakDetector {
  constructor(threshold = 50 * 1024 * 1024) { // 50MB
    this.threshold = threshold;
    this.samples = [];
    this.start();
  }

  start() {
    setInterval(() => {
      const usage = process.memoryUsage();
      this.samples.push(usage.heapUsed);

      // 直近10サンプルで増加傾向をチェック
      if (this.samples.length > 10) {
        const recent = this.samples.slice(-10);
        const trend = this.calculateTrend(recent);

        if (trend > this.threshold) {
          console.warn('メモリリークの可能性を検出しました');
          this.generateHeapDump();
        }

        // 古いサンプルを削除
        if (this.samples.length > 100) {
          this.samples = this.samples.slice(-50);
        }
      }
    }, 10000);
  }

  calculateTrend(samples) {
    const n = samples.length;
    const sumX = n * (n - 1) / 2;
    const sumY = samples.reduce((a, b) => a + b, 0);
    const sumXY = samples.reduce((sum, y, x) => sum + x * y, 0);
    const sumX2 = n * (n - 1) * (2 * n - 1) / 6;

    return (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
  }

  generateHeapDump() {
    // ヒープダンプ生成処理
  }
}

new MemoryLeakDetector();
```

## 6. 予防策

### WeakMapの使用
```javascript
// 強い参照を避ける
const weakMap = new WeakMap();

function attachData(obj, data) {
  weakMap.set(obj, data); // objが削除されればdataも自動削除
}
```

### 適切なストリーム処理
```javascript
const fs = require('fs');

// バッファリングを避ける
function processLargeFile(filename) {
  return new Promise((resolve, reject) => {
    const stream = fs.createReadStream(filename);

    stream.on('data', chunk => {
      // チャンクごとに処理
      processChunk(chunk);
    });

    stream.on('end', resolve);
    stream.on('error', reject);
  });
}
```

これらの方法を組み合わせて、段階的にメモリリークの原因を特定し、対策を講じることができます。特に本番環境では継続的な監視が重要です。

