APIのレート制限を実装する方法をいくつかのアプローチで説明します。

## 1. Token Bucket（トークンバケット）アルゴリズム

最も一般的で推奨される方法です。

### Node.js + Express の実装例

```javascript
class TokenBucket {
  constructor(capacity, refillRate) {
    this.capacity = capacity;      // バケットの最大容量
    this.tokens = capacity;        // 現在のトークン数
    this.refillRate = refillRate;  // 1秒あたりの補充レート
    this.lastRefill = Date.now();
  }

  consume(tokens = 1) {
    this.refill();
    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  refill() {
    const now = Date.now();
    const timePassed = (now - this.lastRefill) / 1000;
    const tokensToAdd = timePassed * this.refillRate;

    this.tokens = Math.min(this.capacity, this.tokens + tokensToAdd);
    this.lastRefill = now;
  }
}

// Express middleware
const rateLimitMiddleware = (req, res, next) => {
  const clientId = req.ip; // または req.user.id など

  if (!buckets.has(clientId)) {
    buckets.set(clientId, new TokenBucket(10, 1)); // 10リクエスト/秒
  }

  const bucket = buckets.get(clientId);

  if (bucket.consume()) {
    next();
  } else {
    res.status(429).json({
      error: 'Rate limit exceeded',
      retryAfter: Math.ceil((1 - bucket.tokens) / bucket.refillRate)
    });
  }
};
```

## 2. Sliding Window（スライディングウィンドウ）

### Redis を使った実装

```javascript
const redis = require('redis');
const client = redis.createClient();

async function slidingWindowRateLimit(userId, limit, windowSizeMs) {
  const now = Date.now();
  const window = windowSizeMs;
  const key = `rate_limit:${userId}`;

  // 古いエントリを削除
  await client.zremrangebyscore(key, 0, now - window);

  // 現在のリクエスト数を取得
  const currentRequests = await client.zcard(key);

  if (currentRequests >= limit) {
    return { allowed: false, remaining: 0 };
  }

  // 新しいリクエストを記録
  await client.zadd(key, now, `${now}-${Math.random()}`);
  await client.expire(key, Math.ceil(window / 1000));

  return { 
    allowed: true, 
    remaining: limit - currentRequests - 1 
  };
}

// Express middleware
const slidingWindowMiddleware = async (req, res, next) => {
  const userId = req.ip;
  const result = await slidingWindowRateLimit(userId, 100, 60000); // 100req/分

  if (result.allowed) {
    res.set('X-RateLimit-Remaining', result.remaining);
    next();
  } else {
    res.status(429).json({ error: 'Rate limit exceeded' });
  }
};
```

## 3. Fixed Window（固定ウィンドウ）

```javascript
const rateLimitStore = new Map();

function fixedWindowRateLimit(userId, limit, windowSizeMs) {
  const now = Date.now();
  const windowStart = Math.floor(now / windowSizeMs) * windowSizeMs;
  const key = `${userId}:${windowStart}`;

  const current = rateLimitStore.get(key) || 0;

  if (current >= limit) {
    return { 
      allowed: false, 
      resetTime: windowStart + windowSizeMs 
    };
  }

  rateLimitStore.set(key, current + 1);

  // 古いエントリのクリーンアップ
  setTimeout(() => rateLimitStore.delete(key), windowSizeMs);

  return { 
    allowed: true, 
    remaining: limit - current - 1,
    resetTime: windowStart + windowSizeMs
  };
}
```

## 4. 既存ライブラリの使用

### express-rate-limit

```javascript
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15分
  max: 100, // 最大100リクエスト
  message: 'Too many requests, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
  store: new RedisStore({
    // Redis接続設定
  })
});

app.use('/api/', limiter);
```

## 5. レスポンスヘッダーの設定

レート制限の情報をクライアントに伝えるため、以下のヘッダーを設定します：

```javascript
function setRateLimitHeaders(res, limit, remaining, resetTime) {
  res.set({
    'X-RateLimit-Limit': limit,
    'X-RateLimit-Remaining': remaining,
    'X-RateLimit-Reset': Math.ceil(resetTime / 1000),
    'Retry-After': Math.ceil((resetTime - Date.now()) / 1000)
  });
}
```

## 6. 段階的制限の実装

```javascript
const tierLimits = {
  free: { requests: 100, window: 3600000 },    // 100req/時間
  premium: { requests: 1000, window: 3600000 }, // 1000req/時間
  enterprise: { requests: 10000, window: 3600000 } // 10000req/時間
};

function getUserTier(userId) {
  // データベースからユーザーのプランを取得
  return 'free'; // 例
}

const tierBasedRateLimit = (req, res, next) => {
  const userId = req.user.id;
  const tier = getUserTier(userId);
  const limits = tierLimits[tier];

  // レート制限チェック実装
  // ...
};
```

## まとめ

- **Token Bucket**: 一時的なバーストトラフィックに対応可能
- **Sliding Window**: より正確だが実装が複雑
- **Fixed Window**: シンプルだが境界での問題あり

本番環境では、Redisなどの外部ストアを使用して複数のサーバー間でレート制限情報を共有することをお勧めします。

APIのレート制限を実装する方法について、代表的なアルゴリズムとその実装例をご紹介します。

## 主要なレート制限アルゴリズム

### 1. Token Bucket（トークンバケット）
一定の速度でトークンを補充し、リクエスト時にトークンを消費する方式です。

```python
import time
from threading import Lock

class TokenBucket:
    def __init__(self, capacity, refill_rate):
        self.capacity = capacity
        self.tokens = capacity
        self.refill_rate = refill_rate
        self.last_refill = time.time()
        self.lock = Lock()

    def consume(self, tokens=1):
        with self.lock:
            self._refill()
            if self.tokens >= tokens:
                self.tokens -= tokens
                return True
            return False

    def _refill(self):
        now = time.time()
        tokens_to_add = (now - self.last_refill) * self.refill_rate
        self.tokens = min(self.capacity, self.tokens + tokens_to_add)
        self.last_refill = now

# 使用例
bucket = TokenBucket(capacity=10, refill_rate=1)  # 1秒に1トークン補充
```

### 2. Sliding Window（スライディングウィンドウ）
時間窓を細かく区切り、より滑らかな制限を実現します。

```python
import time
from collections import deque

class SlidingWindowRateLimit:
    def __init__(self, limit, window_size):
        self.limit = limit
        self.window_size = window_size
        self.requests = deque()

    def allow_request(self):
        now = time.time()
        # 古いリクエストを削除
        while self.requests and self.requests[0] <= now - self.window_size:
            self.requests.popleft()

        if len(self.requests) < self.limit:
            self.requests.append(now)
            return True
        return False

# 使用例: 1分間に100リクエストまで
rate_limiter = SlidingWindowRateLimit(limit=100, window_size=60)
```

### 3. Fixed Window（固定ウィンドウ）
シンプルで実装が容易な方式です。

```python
import time
from collections import defaultdict

class FixedWindowRateLimit:
    def __init__(self, limit, window_size):
        self.limit = limit
        self.window_size = window_size
        self.windows = defaultdict(int)

    def allow_request(self, user_id):
        current_window = int(time.time()) // self.window_size
        key = f"{user_id}:{current_window}"

        if self.windows[key] < self.limit:
            self.windows[key] += 1
            return True
        return False

    def cleanup_old_windows(self):
        current_window = int(time.time()) // self.window_size
        keys_to_delete = [key for key in self.windows.keys() 
                         if int(key.split(':')[1]) < current_window - 1]
        for key in keys_to_delete:
            del self.windows[key]
```

## Webフレームワークでの実装例

### Flask + Redis
```python
from flask import Flask, request, jsonify
import redis
import time

app = Flask(__name__)
redis_client = redis.Redis(host='localhost', port=6379, db=0)

def rate_limit(max_requests=60, per_seconds=60):
    def decorator(f):
        def wrapper(*args, **kwargs):
            # クライアントIPを取得
            client_ip = request.remote_addr
            key = f"rate_limit:{client_ip}"

            current_time = int(time.time())
            window = current_time // per_seconds
            window_key = f"{key}:{window}"

            current_requests = redis_client.get(window_key)
            if current_requests is None:
                redis_client.setex(window_key, per_seconds, 1)
            else:
                if int(current_requests) >= max_requests:
                    return jsonify({'error': 'Rate limit exceeded'}), 429
                redis_client.incr(window_key)

            return f(*args, **kwargs)
        return wrapper
    return decorator

@app.route('/api/data')
@rate_limit(max_requests=100, per_seconds=60)
def get_data():
    return jsonify({'data': 'Hello World'})
```

### Express.js
```javascript
const express = require('express');
const redis = require('redis');
const app = express();
const client = redis.createClient();

const rateLimit = (maxRequests = 60, windowSeconds = 60) => {
    return async (req, res, next) => {
        const clientIP = req.ip;
        const key = `rate_limit:${clientIP}`;
        const currentTime = Math.floor(Date.now() / 1000);
        const window = Math.floor(currentTime / windowSeconds);
        const windowKey = `${key}:${window}`;

        try {
            const currentRequests = await client.get(windowKey);

            if (!currentRequests) {
                await client.setex(windowKey, windowSeconds, 1);
            } else if (parseInt(currentRequests) >= maxRequests) {
                return res.status(429).json({ error: 'Rate limit exceeded' });
            } else {
                await client.incr(windowKey);
            }

            next();
        } catch (error) {
            next(error);
        }
    };
};

app.use(rateLimit(100, 60)); // 1分間に100リクエスト
```

## 高度な実装のポイント

### 1. 分散環境での対応
```python
# Redis Lua スクリプトを使用した原子的操作
lua_script = """
local key = KEYS[1]
local limit = tonumber(ARGV[1])
local window = tonumber(ARGV[2])
local current = redis.call('GET', key) or 0

if tonumber(current) < limit then
    redis.call('INCR', key)
    redis.call('EXPIRE', key, window)
    return 1
else
    return 0
end
"""

def check_rate_limit(user_id, limit=100, window=60):
    key = f"rate_limit:{user_id}:{int(time.time()) // window}"
    result = redis_client.eval(lua_script, 1, key, limit, window)
    return bool(result)
```

### 2. 階層化レート制限
```python
class TieredRateLimit:
    def __init__(self):
        self.user_limits = {}
        self.global_limit = SlidingWindowRateLimit(1000, 60)  # グローバル制限

    def check_limits(self, user_id, user_type='basic'):
        # グローバル制限チェック
        if not self.global_limit.allow_request():
            return False, "Global rate limit exceeded"

        # ユーザータイプ別制限
        limits = {
            'basic': (10, 60),    # 1分間に10リクエスト
            'premium': (100, 60), # 1分間に100リクエスト
            'enterprise': (1000, 60) # 1分間に1000リクエスト
        }

        limit, window = limits.get(user_type, limits['basic'])

        if user_id not in self.user_limits:
            self.user_limits[user_id] = SlidingWindowRateLimit(limit, window)

        if self.user_limits[user_id].allow_request():
            return True, "OK"
        else:
            return False, f"User rate limit exceeded for {user_type}"
```

これらの実装例を参考に、あなたのアプリケーションの要件に応じて適切なレート制限を実装してください。重要なのは、パフォーマンス、精度、実装の複雑さのバランスを取ることです。

