APIレート制限実装パターン。主要手法3つ。

## Token Bucket

```javascript
class TokenBucket {
  constructor(capacity, refillRate) {
    this.capacity = capacity
    this.tokens = capacity
    this.refillRate = refillRate // tokens/秒
    this.lastRefill = Date.now()
  }

  consume(tokens = 1) {
    this.refill()
    if (this.tokens >= tokens) {
      this.tokens -= tokens
      return true
    }
    return false
  }

  refill() {
    const now = Date.now()
    const elapsed = (now - this.lastRefill) / 1000
    this.tokens = Math.min(this.capacity, 
      this.tokens + elapsed * this.refillRate)
    this.lastRefill = now
  }
}
```

## Sliding Window

Redis使用。正確だが重い。

```javascript
async function checkRateLimit(userId, limit, window) {
  const key = `rate_limit:${userId}`
  const now = Date.now()
  const cutoff = now - window * 1000

  const pipeline = redis.pipeline()
  pipeline.zremrangebyscore(key, 0, cutoff)
  pipeline.zcard(key)
  pipeline.zadd(key, now, now)
  pipeline.expire(key, window)

  const results = await pipeline.exec()
  const currentCount = results[1][1]

  return currentCount < limit
}
```

## Fixed Window

シンプル。バースト許可問題あり。

```javascript
const windows = new Map()

function checkFixedWindow(userId, limit, windowSec) {
  const now = Math.floor(Date.now() / 1000)
  const windowStart = Math.floor(now / windowSec) * windowSec
  const key = `${userId}:${windowStart}`

  const count = windows.get(key) || 0
  if (count >= limit) return false

  windows.set(key, count + 1)
  // 古いエントリ削除ロジック追加
  return true
}
```

## Express middleware実装

```javascript
function rateLimit(options) {
  const bucket = new Map()

  return (req, res, next) => {
    const key = req.ip // またはuser ID

    if (!bucket.has(key)) {
      bucket.set(key, new TokenBucket(options.limit, options.rate))
    }

    if (bucket.get(key).consume()) {
      next()
    } else {
      res.status(429).json({ 
        error: "Rate limit exceeded",
        retryAfter: Math.ceil(options.limit / options.rate)
      })
    }
  }
}

// 使用例
app.use(rateLimit({ limit: 100, rate: 10 })) // 100req容量、10req/秒補充
```

## 選択指針

- **Token Bucket**: バーストトラフィック許可したい
- **Sliding Window**: 正確性重要、Redis使える  
- **Fixed Window**: シンプル実装、多少不正確OK

本番環境はRedis + Sliding Window推奨。

APIのレート制限実装方法。主要パターン3つ:

## Token Bucket
リクエスト = トークン消費。バケツに一定速度でトークン補充。

```javascript
class TokenBucket {
  constructor(capacity, refillRate) {
    this.capacity = capacity;
    this.tokens = capacity;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  consume() {
    this.refill();
    if (this.tokens > 0) {
      this.tokens--;
      return true;
    }
    return false;
  }

  refill() {
    const now = Date.now();
    const elapsed = (now - this.lastRefill) / 1000;
    this.tokens = Math.min(
      this.capacity, 
      this.tokens + elapsed * this.refillRate
    );
    this.lastRefill = now;
  }
}
```

## Fixed Window
時間窓でカウント。シンプル、メモリ効率良。

```javascript
// Redis使用例
async function checkRateLimit(userId, limit = 100, windowSec = 3600) {
  const key = `rate:${userId}:${Math.floor(Date.now() / 1000 / windowSec)}`;
  const current = await redis.incr(key);
  if (current === 1) await redis.expire(key, windowSec);
  return current <= limit;
}
```

## Sliding Window Log
精密制御。各リクエスト時刻記録。

```javascript
async function slidingWindowCheck(userId, limit, windowMs) {
  const now = Date.now();
  const key = `sliding:${userId}`;

  // 古いエントリ削除
  await redis.zremrangebyscore(key, 0, now - windowMs);

  // 現在数チェック
  const current = await redis.zcard(key);
  if (current >= limit) return false;

  // 新エントリ追加
  await redis.zadd(key, now, `${now}-${Math.random()}`);
  await redis.expire(key, Math.ceil(windowMs / 1000));

  return true;
}
```

## Express middleware例

```javascript
function rateLimit(limiter) {
  return async (req, res, next) => {
    const allowed = await limiter.check(req.ip);

    if (!allowed) {
      return res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: limiter.getRetryAfter()
      });
    }

    next();
  };
}

app.use('/api', rateLimit(new TokenBucket(100, 1)));
```

## 実装選択基準

- **Token Bucket**: バースト許可必要
- **Fixed Window**: シンプル、高性能必要  
- **Sliding Window**: 精密制御必要

Redis使用で分散対応。メモリ内実装は単一サーバのみ。

