const checkRateLimit = async (key, limit, window) => {
  const now = Date.now();
  const pipeline = redis.pipeline();

  // 古いエントリ削除
  pipeline.zremrangebyscore(key, '-inf', now - window * 1000);
  // 現在リクエスト追加
  pipeline.zadd(key, now, `${now}-${Math.random()}`);
  // カウント取得
  pipeline.zcard(key);
  pipeline.expire(key, window);

  const results = await pipeline.exec();
  const count = results[2][1];

  return count <= limit;
};
```

用途別選択:
- **軽量**: Token Bucket (メモリ)
- **分散**: Redis sliding window
- **厳密**: Fixed window counter

レート制限 実装方法:

## Token Bucket
```javascript
class TokenBucket {
  constructor(capacity, refillRate) {
    this.capacity = capacity;
    this.tokens = capacity;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  consume() {
    this.refill();
    if (this.tokens > 0) {
      this.tokens--;
      return true;
    }
    return false;
  }

  refill() {
    const now = Date.now();
    const tokensToAdd = Math.floor((now - this.lastRefill) / 1000 * this.refillRate);
    this.tokens = Math.min(this.capacity, this.tokens + tokensToAdd);
    this.lastRefill = now;
  }
}
```

## Fixed Window
Redis使用:
```javascript
async function checkRateLimit(userId, limit, window) {
  const key = `rate_limit:${userId}:${Math.floor(Date.now() / window)}`;
  const current = await redis.incr(key);
  if (current === 1) {
    await redis.expire(key, Math.ceil(window / 1000));
  }
  return current <= limit;
}
```

## Sliding Window Log
```javascript
async function slidingWindowLog(userId, limit, window) {
  const key = `log:${userId}`;
  const now = Date.now();
  const cutoff = now - window;

  await redis.zremrangebyscore(key, 0, cutoff);
  const count = await redis.zcard(key);

  if (count < limit) {
    await redis.zadd(key, now, now);
    return true;
  }
  return false;
}
```

Express middleware例:
```javascript
const rateLimiter = (limit, window) => {
  return async (req, res, next) => {
    const allowed = await checkRateLimit(req.ip, limit, window);
    if (!allowed) {
      return res.status(429).json({ error: 'Rate limit exceeded' });
    }
    next();
  };
};

app.use('/api', rateLimiter(100, 60000)); // 100req/min
```

Token Bucket = バースト許可。Fixed Window = 実装簡単。Sliding = 正確だがメモリ使用大。

レート制限 実装パターン:

**Token Bucket**
```javascript
class TokenBucket {
  constructor(capacity, refillRate) {
    this.capacity = capacity;
    this.tokens = capacity;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  consume(tokens = 1) {
    this.refill();
    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  refill() {
    const now = Date.now();
    const tokensToAdd = ((now - this.lastRefill) / 1000) * this.refillRate;
    this.tokens = Math.min(this.capacity, this.tokens + tokensToAdd);
    this.lastRefill = now;
  }
}
```

**Redis sliding window**
```javascript
async function checkRateLimit(userId, limit, windowMs) {
  const key = `rate_limit:${userId}`;
  const now = Date.now();
  const windowStart = now - windowMs;

  // 古いエントリ削除
  await redis.zremrangebyscore(key, 0, windowStart);

  // 現在リクエスト数取得
  const requestCount = await redis.zcard(key);

  if (requestCount >= limit) {
    return false; // レート制限
  }

  // 新リクエスト記録
  await redis.zadd(key, now, now);
  await redis.expire(key, Math.ceil(windowMs / 1000));

  return true;
}
```

**Express middleware**
```javascript
const rateLimit = (windowMs, max) => {
  const clients = new Map();

  return (req, res, next) => {
    const key = req.ip;
    const now = Date.now();
    const windowStart = now - windowMs;

    if (!clients.has(key)) {
      clients.set(key, []);
    }

    const requests = clients.get(key);
    const validRequests = requests.filter(time => time > windowStart);

    if (validRequests.length >= max) {
      return res.status(429).json({ error: 'Too many requests' });
    }

    validRequests.push(now);
    clients.set(key, validRequests);
    next();
  };
};
```

レスポンスヘッダー追加:
```javascript
res.setHeader('X-RateLimit-Limit', max);
res.setHeader('X-RateLimit-Remaining', max - validRequests.length);
res.setHeader('X-RateLimit-Reset', new Date(windowStart + windowMs));
```

Redis > メモリ。分散環境対応。Token Bucket = バースト許可。Sliding Window = 厳密制御。
